import{_ as s,o as t,c as r,a2 as a}from"./chunks/framework.Crpw6aS5.js";const p=JSON.parse('{"title":"Vie privée","description":"","frontmatter":{},"headers":[],"relativePath":"fr/guide/privacy.md","filePath":"fr/guide/privacy.md"}'),n={name:"fr/guide/privacy.md"};function i(o,e,l,c,d,u){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="vie-privee" tabindex="-1">Vie privée <a class="header-anchor" href="#vie-privee" aria-label="Permalink to &quot;Vie privée&quot;">​</a></h1><p>Nid intègre des outils pour protéger votre vie privée : détection de pixels espions, scanner de données sensibles et chiffrement de vos archives.</p><hr><h2 id="detection-de-pixels-espions-tracking" tabindex="-1">Détection de pixels espions (tracking) <a class="header-anchor" href="#detection-de-pixels-espions-tracking" aria-label="Permalink to &quot;Détection de pixels espions (tracking)&quot;">​</a></h2><p>De nombreux mails commerciaux contiennent des <strong>pixels espions</strong> : des images invisibles qui signalent à l&#39;expéditeur quand vous ouvrez le mail.</p><h3 id="scanner-vos-mails" tabindex="-1">Scanner vos mails <a class="header-anchor" href="#scanner-vos-mails" aria-label="Permalink to &quot;Scanner vos mails&quot;">​</a></h3><ol><li>Ouvrez la page <strong>Vie privée</strong> dans la sidebar</li><li>Dans l&#39;onglet <strong>Pixels espions</strong>, cliquez sur <strong>Scanner</strong></li><li>Un job de scan est lancé — il analyse le HTML de vos mails récents</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : onglet Pixels espions avec le bouton Scanner et les statistiques globales</em></p></blockquote><h3 id="resultats" tabindex="-1">Résultats <a class="header-anchor" href="#resultats" aria-label="Permalink to &quot;Résultats&quot;">​</a></h3><p>Après le scan, vous voyez :</p><ul><li><strong>Statistiques globales</strong> : nombre de mails contenant des trackers, nombre total de trackers détectés</li><li><strong>Liste par mail</strong> : chaque mail avec le nombre et le type de trackers détectés</li><li><strong>Domaines les plus fréquents</strong> : classement des domaines de tracking (ex. : Mailchimp, SendGrid, HubSpot)</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : résultats du scan avec la liste des mails contenant des trackers et les domaines détectés</em></p></blockquote><h3 id="types-de-trackers-detectes" tabindex="-1">Types de trackers détectés <a class="header-anchor" href="#types-de-trackers-detectes" aria-label="Permalink to &quot;Types de trackers détectés&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Pixels 1×1</strong></td><td>Images invisibles (1 pixel) chargées au moment de l&#39;ouverture</td></tr><tr><td><strong>Domaines connus</strong></td><td>Plus de 35 domaines d&#39;email marketing identifiés (Mailchimp, SendGrid, HubSpot, Klaviyo, Brevo, etc.)</td></tr><tr><td><strong>Paramètres UTM</strong></td><td>Liens contenant des paramètres de tracking (utm_source, utm_medium, utm_campaign)</td></tr></tbody></table><hr><h2 id="scanner-de-donnees-sensibles-pii" tabindex="-1">Scanner de données sensibles (PII) <a class="header-anchor" href="#scanner-de-donnees-sensibles-pii" aria-label="Permalink to &quot;Scanner de données sensibles (PII)&quot;">​</a></h2><p>Le scanner PII (Personally Identifiable Information) analyse vos mails archivés pour détecter les données sensibles en clair.</p><h3 id="scanner-vos-archives" tabindex="-1">Scanner vos archives <a class="header-anchor" href="#scanner-vos-archives" aria-label="Permalink to &quot;Scanner vos archives&quot;">​</a></h3><ol><li>Dans l&#39;onglet <strong>Données sensibles</strong>, cliquez sur <strong>Scanner</strong></li><li>Un job de scan analyse les fichiers EML de vos archives</li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : onglet Données sensibles avec le bouton Scanner</em></p></blockquote><h3 id="types-de-donnees-detectees" tabindex="-1">Types de données détectées <a class="header-anchor" href="#types-de-donnees-detectees" aria-label="Permalink to &quot;Types de données détectées&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Exemple</th></tr></thead><tbody><tr><td><strong>Carte bancaire</strong></td><td>Visa, Mastercard, Amex (avec séparateurs)</td></tr><tr><td><strong>IBAN</strong></td><td>Numéro de compte bancaire international</td></tr><tr><td><strong>Numéro de sécu</strong></td><td>Numéro de sécurité sociale français</td></tr><tr><td><strong>Mot de passe en clair</strong></td><td>Texte contenant &quot;password:&quot;, &quot;mdp=&quot;, etc.</td></tr><tr><td><strong>Téléphone</strong></td><td>Numéro français (+33, 06, 07...)</td></tr></tbody></table><blockquote><p>📸 <em>Capture d&#39;écran suggérée : résultats du scan PII avec le type de donnée, le nombre de mails concernés et un snippet masqué</em></p></blockquote><div class="info custom-block"><p class="custom-block-title">Données masquées</p><p>Les extraits affichés dans les résultats sont automatiquement masqués (ex. : <code>****-****-****-4242</code>) pour ne pas exposer les données réelles dans l&#39;interface.</p></div><hr><h2 id="chiffrement-des-archives" tabindex="-1">Chiffrement des archives <a class="header-anchor" href="#chiffrement-des-archives" aria-label="Permalink to &quot;Chiffrement des archives&quot;">​</a></h2><p>Vos archives EML peuvent être chiffrées sur le NAS avec un algorithme <strong>AES-256-GCM</strong> (le même standard utilisé par les banques et gouvernements).</p><h3 id="configurer-le-chiffrement" tabindex="-1">Configurer le chiffrement <a class="header-anchor" href="#configurer-le-chiffrement" aria-label="Permalink to &quot;Configurer le chiffrement&quot;">​</a></h3><ol><li>Dans l&#39;onglet <strong>Chiffrement</strong>, cliquez sur <strong>Configurer</strong></li><li>Choisissez une <strong>phrase secrète</strong> (passphrase)</li><li>Confirmez la phrase secrète</li><li>Cliquez sur <strong>Activer le chiffrement</strong></li></ol><blockquote><p>📸 <em>Capture d&#39;écran suggérée : formulaire de configuration du chiffrement avec le champ passphrase</em></p></blockquote><div class="warning custom-block"><p class="custom-block-title">Conservez votre phrase secrète</p><p>La phrase secrète n&#39;est <strong>jamais stockée</strong> dans l&#39;application — seul un hash de vérification est conservé. Si vous la perdez, il sera impossible de déchiffrer vos archives. Notez-la dans un endroit sûr (gestionnaire de mots de passe, etc.).</p></div><h3 id="chiffrer-les-archives-existantes" tabindex="-1">Chiffrer les archives existantes <a class="header-anchor" href="#chiffrer-les-archives-existantes" aria-label="Permalink to &quot;Chiffrer les archives existantes&quot;">​</a></h3><p>Après avoir configuré la passphrase :</p><ol><li>Cliquez sur <strong>Chiffrer les archives</strong></li><li>Un job de chiffrement est lancé</li><li>Chaque fichier EML est chiffré individuellement sur le disque</li></ol><p>Les mails déjà chiffrés sont automatiquement ignorés (idempotent).</p><h3 id="lire-un-mail-chiffre" tabindex="-1">Lire un mail chiffré <a class="header-anchor" href="#lire-un-mail-chiffre" aria-label="Permalink to &quot;Lire un mail chiffré&quot;">​</a></h3><p>Quand vous consultez un mail chiffré dans la page Archives, il est <strong>déchiffré à la volée</strong> dans la mémoire du serveur. Le fichier reste chiffré sur le disque en permanence.</p><h3 id="statut-du-chiffrement" tabindex="-1">Statut du chiffrement <a class="header-anchor" href="#statut-du-chiffrement" aria-label="Permalink to &quot;Statut du chiffrement&quot;">​</a></h3><p>L&#39;onglet Chiffrement affiche :</p><ul><li>Si une passphrase est configurée</li><li>Le nombre de mails chiffrés / non chiffrés</li><li>Un indicateur de sécurité global</li></ul><blockquote><p>📸 <em>Capture d&#39;écran suggérée : statut du chiffrement avec le nombre de mails chiffrés et le pourcentage</em></p></blockquote>',41)])])}const m=s(n,[["render",i]]);export{p as __pageData,m as default};
